mapper.select:
SELECT t.pause_id AS pauseId, t.user_id AS userId, u.nickname AS nickname, u.phone AS phone, t.card_order_id AS cardOrderId, fc.cardName AS cardName, t.pause_type AS pauseType, t.amount AS amount, t.pay_order_no AS payOrderNo, DATE_FORMAT(t.start_time, '%Y-%m-%d %H:%i:%s') AS startTime, DATE_FORMAT(t.end_time, '%Y-%m-%d %H:%i:%s') AS endTime, DATE_FORMAT(t.cancel_time, '%Y-%m-%d %H:%i:%s') AS cancelTime, t.pause_days AS pauseDays, t.actual_days AS actualDays, t.status AS status, AS displayStatus, DATE_FORMAT(t.created_date, '%Y-%m-%d %H:%i:%s') AS createdDate FROM card_pause_record t LEFT JOIN user_info u ON t.user_id = u.userId LEFT JOIN card_order co ON t.card_order_id = co.cardOrderId LEFT JOIN fit_card fc ON co.cardId = fc.fitCardId
ORDER BY t.created_date DESC
LIMIT #{offset}, #{limit}
